import{_ as a}from"./chunks/xuanji-cover.CaJrYJ75.js";import{_ as t,o as r,c as n,ai as o}from"./chunks/framework.DyvBZb4W.js";const p=JSON.parse('{"title":"Xuanji Character Mod","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/xuanji-character/index.md","filePath":"en/mods/xuanji-character/index.md","lastUpdated":1779031942000}'),s={name:"en/mods/xuanji-character/index.md"};function i(d,e,c,l,g,h){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="xuanji-character-mod" tabindex="-1">Xuanji Character Mod <a class="header-anchor" href="#xuanji-character-mod" aria-label="Permalink to &quot;Xuanji Character Mod&quot;">​</a></h1><p>Xuanji is a male custom character mod for Slay the Spire 2. His combat loop is built around playing cards, encoding them into a Machine Chamber, condensing Machine Cores, and using those cores to turn synergy progress into a long-running engine.</p><figure><img src="'+a+'" alt="Xuanji Character Mod cover"><figcaption>Encode. Condense. Synergize.</figcaption></figure><p>Current version: <code>0.3.0-beta</code><br> Release status: Beta<br> Author: Jason Song<br> Type: custom character / synergy-building / Machine Core planning<br> Gameplay impact: yes. It adds a new character, custom cards, custom relics, and new build directions.</p><h2 id="gameplay-overview" tabindex="-1">Gameplay Overview <a class="header-anchor" href="#gameplay-overview" aria-label="Permalink to &quot;Gameplay Overview&quot;">​</a></h2><p>Xuanji is not built around one oversized burst card. His core gameplay is about laying down tagged cards, encoding them into the Machine Chamber, condensing those cards into Machine Cores, then letting multiple synergies trigger across turn start, encoding, condensing, drawing, exhausting, and combat victory.</p><ul><li><strong>Encode</strong>: encoded cards enter the Machine Chamber after being played. Once encoded, they no longer contribute synergies again during the same combat.</li><li><strong>Machine Chamber</strong>: holds cards waiting to be condensed. Chamber order matters, so arranging the chamber is part of the tactical puzzle.</li><li><strong>Condense</strong>: when the chamber reaches 3 cards, they become a Machine Core. Cores provide synergy progress and can establish a main combat identity.</li><li><strong>Retuning</strong>: some cards move, remove, replace, or add tags, letting players correct the next core instead of simply waiting for it.</li><li><strong>Momentum growth</strong>: some routes turn combat planning into Gold, Max HP, deck upgrades, Replay, or future-combat bonuses.</li></ul><p>In a normal run, you are not expected to max every synergy. The more interesting choice is deciding whether the deck needs defense, burst, draw, Energy, exhaust payoffs, poison and debuffs, long-term growth, or multi-synergy chaining, then drafting and condensing around that plan.</p><h2 id="main-synergies" tabindex="-1">Main Synergies <a class="header-anchor" href="#main-synergies" aria-label="Permalink to &quot;Main Synergies&quot;">​</a></h2><p>The current version has 8 synergies. This overview focuses on the main routes instead of listing every card.</p><table tabindex="0"><thead><tr><th>Synergy</th><th>Direction</th><th>Main Effects</th></tr></thead><tbody><tr><td>Bulwark</td><td>Defense, Block scaling</td><td>Bulwark cores provide Block at turn start. Higher progress adds extra Block when cards grant Block, can preserve Block, and eventually reflects attack damage back to enemies.</td></tr><tr><td>Ambush</td><td>Attack rhythm, burst</td><td>Ambush cores empower the first attack each turn. Higher progress grants Vigor, temporary Strength, and eventually creates an extra attack card at turn start.</td></tr><tr><td>Insight</td><td>Draw, hand filtering</td><td>Insight cores draw when you encode. Higher progress adds turn-start draw, draw after the first encode each turn, discard/exhaust choices, and eventually turns drawing into area damage.</td></tr><tr><td>Overload</td><td>Energy, stored burst</td><td>Overload cores grant Energy after condensing. Higher progress adds more Energy, preserves unspent Energy, and can convert current Energy into damage to all enemies.</td></tr><tr><td>Momentum</td><td>Long-term growth</td><td>Momentum cores earn Gold on turns where you do not condense. Higher progress grants Max HP after combat, upgrades deck cards or adds Replay, and builds a Momentum Emblem for future-combat bonuses.</td></tr><tr><td>Transmute</td><td>Exhaust, resource loops</td><td>Transmute cores turn Exhaust into draw. Higher progress turns encoding and exhausting into card draw, Energy, and random 0-cost Exhaust cards.</td></tr><tr><td>Corrosion</td><td>Poison, Weak, Vulnerable</td><td>Corrosion cores apply Poison at turn start. Higher progress adds Weak and Vulnerable, expands target coverage, and can eventually apply a large amount of Poison to all enemies.</td></tr><tr><td>Command</td><td>Multi-synergy engine</td><td>Command cores trigger when other main cores trigger. Higher progress rewards other synergy triggers with Block, draw, Energy, damage, and extra synergy progress.</td></tr></tbody></table><h2 id="build-directions" tabindex="-1">Build Directions <a class="header-anchor" href="#build-directions" aria-label="Permalink to &quot;Build Directions&quot;">​</a></h2><p>Xuanji decks are closer to planning a small machine than finding one single payoff. Common directions include:</p><ul><li><strong>Bulwark + Insight</strong> for stable defense, draw, and turn quality.</li><li><strong>Ambush + Overload</strong> to convert Energy and first-attack bonuses into fast kills.</li><li><strong>Transmute + Insight</strong> for draw, exhaust, and 0-cost resource loops.</li><li><strong>Corrosion + Momentum</strong> for sustained pressure and long-term growth.</li><li><strong>Command</strong> as the glue for decks that want several active cores and many synergy triggers.</li></ul><h2 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h2><ul><li>Requires <code>BaseLib v3.1.0</code>.</li><li>The current build has compatibility handling for the locally available Slay the Spire 2 <code>v0.103.2</code> stable branch and the <code>v0.105.x</code> beta API line.</li><li>This is a Beta release, so balance values, card distribution, and UI details may continue to change based on feedback.</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Back to <a href="/jasonsong-games/en/mods/">All Mods</a></li></ul>',18)])])}const y=t(s,[["render",i]]);export{p as __pageData,y as default};
